const body = $input.first().json.body || $input.first().json;
const imageDataUrl = body.image || '';
const boxId = body.boxId || '';
if (!imageDataUrl) throw new Error('缺少 image 欄位');

let base64String, mimeType;
if (imageDataUrl.startsWith('data:')) {
  const match = imageDataUrl.match(/^data:(.+?);base64,(.+)$/);
  if (match) { mimeType = match[1]; base64String = match[2]; }
  else throw new Error('無效的 data URL');
} else { base64String = imageDataUrl; mimeType = 'image/jpeg'; }

const prompt = '你是專業的商品條碼標籤 OCR 辨識系統。請辨識商品條碼標籤上印刷的文字資訊。

標籤有多種格式，以下是常見範例：

【格式A】分行排列：
條碼編號（純數字）
商品品名
性別　顏色+尺寸
[一維條碼圖形]
範例：「1801080204 / 第五代溫灸刷毛圓領發熱衣 / 女　經典黑L」

【格式B】品名後括號內含所有屬性：
條碼編號
商品品名(顏色 性別 尺寸)
[一維條碼圖形]
範例：「1801472364 / 搖粒絨極暖衝鋒褲(星夜黑 男女共版 L)」

【格式C】括號內用連字號分隔：
[一維條碼圖形]
條碼編號
商品品名(性別-顏色 尺寸)
範例：「1801872396 / 熱導石墨烯輕羽絨衣(中性-晨霧灰 2XL)」

【格式D】括號內顏色+性別尺寸連寫：
商品品名(顏色 性別+尺寸)
[一維條碼圖形]
條碼編號
範例：「素面防曬排汗短版涼感衣(戀愛粉 女XL) / 1037720345」

請辨識並回傳以下欄位（純 JSON，不含 markdown 標記）：
{"barcode":"條碼數字編號","productName":"商品名稱（不含括號內容）","gender":"男 或 女 或 中性","color":"顏色名稱","size":"尺寸代碼"}

重要規則：
- productName 只取括號前的商品名稱，不含括號及括號內的屬性文字
- 「男女共版」視為「中性」
- 性別可能是：男、女、中性、男女共版
- 尺寸為英文字母或數字（S、M、L、XL、XXL、2XL、3XL、F 等）
- 顏色是中文描述（如「星夜黑」「晨霧灰」「戀愛粉」「經典黑」「深藍」等）
- 括號內的分隔方式不固定：可能是空格、連字號、或直接連寫
- 如果某欄位看不清楚或不存在，回傳空字串';

return [{
  json: {
    boxId,
    requestBody: JSON.stringify({
      model: 'gpt-4o-mini',
      max_tokens: 300,
      temperature: 0.1,
      messages: [
        { role: 'system', content: prompt },
        { role: 'user', content: [
          { type: 'text', text: '請辨識這張商品條碼標籤上的所有文字資訊。' },
          { type: 'image_url', image_url: { url: `data:${mimeType};base64,${base64String}`, detail: 'auto' } }
        ]}
      ]
    })
  }
}];

const response = $input.first().json;
const boxId = $('組裝請求').first().json.boxId;
const content = response.choices[0].message.content;
let clean = content.trim();
if (clean.startsWith('```json')) clean = clean.replace(/^```json\n?/, '').replace(/\n?```$/, '');
else if (clean.startsWith('```')) clean = clean.replace(/^```\n?/, '').replace(/\n?```$/, '');
let data;
try { data = JSON.parse(clean); } catch(e) {
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) data = JSON.parse(m[0]); else throw new Error('OCR parse fail');
}
const gender = (data.gender === '男女共版') ? '中性' : (data.gender || '');

// 台北時間
const now = new Date();
const taipeiTime = new Date(now.getTime() + 8*60*60*1000);
const dateOnly = taipeiTime.toISOString().substring(0, 10).replace(/-/g, '/');
const fullTime = taipeiTime.toISOString().replace('T', ' ').substring(0, 19);

return [{ json: {
  barcode: data.barcode || '',
  productName: data.productName || '',
  gender: gender,
  color: data.color || '',
  size: data.size || '',
  boxId: boxId,
  日期: dateOnly,
  辨識時間: fullTime
}}];
